import React, { useState } from "react";
import { motion } from "framer-motion";

const cardStyle = {
  width: 260,
  height: 280,
  perspective: 1000,
  cursor: "pointer",
  userSelect: "none",
};

const cardInnerStyle = (flipped) => ({
  position: "relative",
  width: "100%",
  height: "100%",
  borderRadius: "1rem",
  boxShadow: "0 0 15px rgba(0,0,0,0.15)",
  transformStyle: "preserve-3d",
  transition: "transform 0.6s",
  transform: flipped ? "rotateY(180deg)" : "rotateY(0deg)",
  backgroundColor: "#154734",
  color: "#e4d0a9",
  display: "flex",
  flexDirection: "column",
  justifyContent: "center",
  padding: "1.5rem",
});

const cardFrontBackCommon = {
  position: "absolute",
  width: "100%",
  height: "100%",
  borderRadius: "1rem",
  backfaceVisibility: "hidden",
  display: "flex",
  flexDirection: "column",
  justifyContent: "center",
  alignItems: "center",
  padding: "1.5rem",
};

const cardFrontStyle = {
  ...cardFrontBackCommon,
};

const cardBackStyle = {
  ...cardFrontBackCommon,
  transform: "rotateY(180deg)",
  textAlign: "center",
};

const TestimonialCard = ({ card }) => {
  const [flipped, setFlipped] = useState(false);

  return (
    <div style={cardStyle} onClick={() => setFlipped(!flipped)}>
      <motion.div style={cardInnerStyle(flipped)}>
        {/* Front Side */}
        <div style={cardFrontStyle}>
          <h3 style={{ fontSize: "1.8rem", marginBottom: "1rem" }}>{card.title}</h3>
          <p style={{ flexGrow: 1, fontSize: "1rem", lineHeight: "1.4" }}>{card.text}</p>
          <strong style={{ marginTop: "1rem", fontSize: "1.1rem" }}>{card.role}</strong>
        </div>

        {/* Back Side */}
        <div style={cardBackStyle}>
          {card.backType === "list" ? (
            <ul style={{ listStyleType: "none", padding: 0, margin: 0, overflowY: "auto", maxHeight: 200 }}>
              {card.backContent && card.backContent.map && card.backContent.map((item, i) => (
                <li key={i} style={{ marginBottom: "0.3rem", fontSize: "1rem" }}>
                  {item}
                </li>
              ))}
            </ul>
          ) : (
            <img
              src={card.backContent}
              alt="Profile"
              style={{ width: 100, height: 100, borderRadius: "50%", objectFit: "cover" }}
            />
          )}
        </div>
      </motion.div>
    </div>
  );
};

export default TestimonialCard;
